import collections

class Graph:
    def __init__(self, num_vertices):
        self.num_vertices = num_vertices
        self.adj = collections.defaultdict(list)

    def add_edge(self, u, v):
        if 0 <= u < self.num_vertices and 0 <= v < self.num_vertices:
            self.adj[u].append(v)
            self.adj[v].append(u)
        else:
            raise ValueError("Vertex out of bounds")

def find_independent_set(graph):
    vertices = list(range(graph.num_vertices))
    best_mis = []

    def _recursive_find_mis(index, current_mis):
        nonlocal best_mis

        # Pruning: If it's impossible to beat the current best_mis even if all remaining
        # vertices are added, then stop.
        if len(current_mis) + (graph.num_vertices - index) <= len(best_mis):
            return

        # Base case: All vertices have been considered.
        if index == graph.num_vertices:
            if len(current_mis) > len(best_mis):
                best_mis = list(current_mis) # Make a copy
            return

        v = vertices[index]

        # Option 1: Try to include the current vertex (v)
        is_compatible = True
        for u_in_mis in current_mis:
            if v in graph.adj[u_in_mis]:
                is_compatible = False
                break

        if is_compatible:
            current_mis.append(v)
            _recursive_find_mis(index + 1, current_mis)
            current_mis.pop() # Backtrack

        # Option 2: Exclude the current vertex (v)
        _recursive_find_mis(index + 1, current_mis)

    _recursive_find_mis(0, [])
    return best_mis
